create table dirkspzm32.isi_artikel_kunde (
    sid                varchar2(2 char) default '01' not null enable,
    artikel_id         number(*, 0) not null enable,
    kunden_nr          varchar2(20 char) not null enable,
    kd_art_nr          varchar2(30 char),
    kd_art_text1       varchar2(50 char),
    kd_art_text2       varchar2(50 char),
    kd_verpackungstype varchar2(10 char),
    lhm_name           varchar2(50 char),
    lhm_menge          number(*, 3),
    lhm_gewicht_kg     number(*, 6),
    lhm_ean            varchar2(15 char),
    lte_name           varchar2(22 char),
    lte_menge          number(*, 3),
    lte_gewicht_kg     number(*, 6),
    lte_breite_max     number(*, 3),
    lte_tiefe_max      number(*, 3),
    lte_hoehe_max      number(*, 3),
    lte_lhm_menge      number(*, 3),
    lte_lhm_pro_lage   number(*, 0),
    lte_lhm_lagen      number(*, 0),
    lte_ean            varchar2(15 char),
    ean                varchar2(15 char),
    firma_nr           number default 1 not null enable,
    lhm_hoehe_lage     number(*, 3),
    stk_liste_txt      varchar2(2000 char),
    packschema_kopf_id varchar2(20 char),
    art_laenge         number(*, 3),
    art_breite         number(*, 3),
    art_dicke          number(*, 3),
    art_durch          number(*, 3),
    pack_vorschr       varchar2(15 char),
    verk_preis         number(*, 5),
    verk_rabatt_faktor number(*, 6)
);

alter table dirkspzm32.isi_artikel_kunde
    add constraint pk_isi_artikel_kunde primary key ( artikel_id,
                                                      kunden_nr )
        using index enable;

alter table dirkspzm32.isi_artikel_kunde add constraint uk_isi_artikel_kd_art unique ( kunden_nr,
                                                                                       kd_art_nr ) disable;


